/**
 * Knowledge Graph System for Semantic Memory Retrieval
 * 
 * Extends the LTM with a graph structure enabling:
 * - Entity and relationship extraction
 * - Graph traversal for memory discovery
 * - Semantic similarity search
 * - Spontaneous "flashback" activation
 * 
 * Architecture:
 * - Nodes: Memories, Concepts, Projects, Tags (with embeddings)
 * - Edges: Relational links with weights
 * - Activation: Nodes can activate, spreading to neighbors (flashback mechanism)
 */

export enum NodeType {
  MEMORY = "memory",
  CONCEPT = "concept",
  PROJECT = "project",
  TAG = "tag",
  ENTITY = "entity",
}

export enum RelationType {
  RELATES_TO = "relates_to",
  PART_OF = "part_of",
  DEPENDS_ON = "depends_on",
  HAS_TAG = "has_tag",
  SIMILAR_TO = "similar_to",
  REMINDS_OF = "reminds_of",
}

export interface NodeProperties {
  content?: string;
  confidence?: number;
  embedding?: number[];
  lastAccessed?: number;
  accessCount?: number;
  createdAt?: number;
  [key: string]: any;
}

export interface EdgeProperties {
  weight?: number;
  [key: string]: any;
}

export interface Node {
  id: string;
  type: NodeType;
  properties: NodeProperties;
  activation: number; // 0-1 for flashback mechanism
}

export interface Edge {
  sourceId: string;
  targetId: string;
  type: RelationType;
  properties: EdgeProperties;
}

export interface MemoryInput {
  id: string;
  content: string;
  tags?: string[];
  confidence?: number;
  category?: string;
  embedding?: number[];
}

export class KnowledgeGraph {
  private nodes: Map<string, Node> = new Map();
  private edges: Map<string, Edge[]> = new Map(); // sourceId -> edges[]
  private readonly DEFAULT_ACTIVATION_DECAY = 0.1;
  private readonly MIN_ACTIVATION_THRESHOLD = 0.5;

  addNode(id: string, type: NodeType, properties: NodeProperties = {}): Node {
    if (this.nodes.has(id)) {
      throw new Error(`Node with ID '${id}' already exists`);
    }
    const node: Node = {
      id,
      type,
      properties: {
        ...properties,
        confidence: properties.confidence ?? 1.0,
        createdAt: properties.createdAt ?? Date.now(),
        lastAccessed: properties.lastAccessed ?? Date.now(),
        accessCount: properties.accessCount ?? 0,
      },
      activation: 0,
    };
    this.nodes.set(id, node);
    this.edges.set(id, []);
    return node;
  }

  getNode(id: string): Node | null {
    return this.nodes.get(id) || null;
  }

  getAllNodes(): Node[] {
    return Array.from(this.nodes.values());
  }

  getNodesByType(type: NodeType): Node[] {
    return this.getAllNodes().filter(n => n.type === type);
  }

  removeNode(id: string): boolean {
    const node = this.nodes.get(id);
    if (!node) return false;

    // Remove all edges connected to this node
    this.edges.delete(id);
    for (const [sourceId, edgeList] of this.edges.entries()) {
      this.edges.set(sourceId, edgeList.filter(e => e.targetId !== id));
    }

    this.nodes.delete(id);
    return true;
  }

  addEdge(
    sourceId: string,
    targetId: string,
    type: RelationType,
    properties: EdgeProperties = {}
  ): Edge {
    if (!this.nodes.has(sourceId)) {
      throw new Error(`Source node '${sourceId}' does not exist`);
    }
    if (!this.nodes.has(targetId)) {
      throw new Error(`Target node '${targetId}' does not exist`);
    }

    const edge: Edge = {
      sourceId,
      targetId,
      type,
      properties: {
        ...properties,
        weight: properties.weight ?? 1.0,
      },
    };

    const existingEdges = this.edges.get(sourceId) || [];
    existingEdges.push(edge);
    this.edges.set(sourceId, existingEdges);

  /**
   * Activate a node and spread activation to neighbors (flashback mechanism)
   */
  activateNode(nodeId: string, amount: number): void {
    const node = this.nodes.get(nodeId);
    if (!node) return;

    node.activation = Math.min(1.0, node.activation + amount);
    node.properties.accessCount = (node.properties.accessCount || 0) + 1;
    node.properties.lastAccessed = Date.now();

    // Spread activation to neighbors
    const nodeEdges = this.edges.get(nodeId) || [];
    for (const edge of nodeEdges) {
      const weight = edge.properties.weight ?? 1.0;
      const spreadAmount = amount * weight * (1 - this.DEFAULT_ACTIVATION_DECAY);
      if (spreadAmount > 0.1) {
        const targetNode = this.nodes.get(edge.targetId);
        if (targetNode) {
          targetNode.activation = Math.min(1.0, targetNode.activation + spreadAmount);
        }
      }
    }
  }

  /**
   * Decay all activations over time
   */
  decayActivation(decayRate: number = 0.1): void {
    for (const node of this.nodes.values()) {
      node.activation = Math.max(0, node.activation - decayRate);
    }
  }

  /**
   * Get currently activated nodes
   */
  getActivatedNodes(threshold: number = 0.3): Node[] {
    return this.getAllNodes()
      .filter(n => n.activation >= threshold)
      .sort((a, b) => b.activation - a.activation);
  }

  /**
   * Generate a "flashback" - spontaneously retrieve an activated memory
   * Prioritizes high-confidence, recently accessed, or strongly activated nodes
   */
  generateFlashback(): Node | null {
    const candidates = this.getAllNodes().filter(n => {
      // Must be a memory node with sufficient confidence
      if (n.type !== NodeType.MEMORY) return false;
      const confidence = n.properties.confidence ?? 0;
      const hasActivation = n.activation > 0.2;
      return confidence >= this.MIN_ACTIVATION_THRESHOLD && (hasActivation || Math.random() < 0.1);
    });

    if (candidates.length === 0) return null;

    // Weighted random selection based on score
    const scored = candidates.map(n => ({
      node: n,
      score: (n.properties.confidence ?? 1.0) * (1 + n.activation) * 
             Math.log(1 + (n.properties.accessCount ?? 0))
    }));

    const totalScore = scored.reduce((sum, s) => sum + s.score, 0);
    let random = Math.random() * totalScore;

    for (const { node, score } of scored) {
      random -= score;
      if (random <= 0) {
        // Boost activation when retrieved
        this.activateNode(node.id, 0.3);
        return node;
      }
    }

    return scored[0]?.node || null;
  }

  /**
   * Build graph from memory entries (LTM integration)
   */
  buildFromMemories(memories: MemoryInput[]): void {
    // Create memory nodes
    for (const mem of memories) {
      if (!this.nodes.has(mem.id)) {
        this.addNode(mem.id, NodeType.MEMORY, {
          content: mem.content,
          confidence: mem.confidence ?? 1.0,
          embedding: mem.embedding,
        });
      }

      // Create tag nodes and edges
      for (const tag of mem.tags || []) {
        const tagId = `tag_${tag}`;
        if (!this.nodes.has(tagId)) {
          this.addNode(tagId, NodeType.TAG, { name: tag });
        }
        this.addEdge(mem.id, tagId, RelationType.HAS_TAG, { weight: 0.8 });
      }
    }

    // Create similarity edges between memories
    this.autoLinkSimilarMemories();
  }

  /**
   * Automatically create edges between similar memories
   */
  autoLinkSimilarMemories(threshold: number = 0.8): number {
    let linksCreated = 0;
    const memories = this.getNodesByType(NodeType.MEMORY)
      .filter(m => m.properties.embedding);

    for (let i = 0; i < memories.length; i++) {
      for (let j = i + 1; j < memories.length; j++) {
        const sim = this.cosineSimilarity(
          memories[i].properties.embedding!,
          memories[j].properties.embedding!
        );
        if (sim >= threshold) {
          this.addEdge(memories[i].id, memories[j].id, RelationType.SIMILAR_TO, { weight: sim });
          linksCreated++;
        }
      }
    }

    return linksCreated;
  }

  /**
   * Recommend related memories based on graph proximity
   */
  recommendRelated(memoryId: string, limit: number = 5): Node[] {
    const startNode = this.nodes.get(memoryId);
    if (!startNode) return [];

    // Get all reachable nodes within 2 hops
    const reachable = this.traverseBFS(memoryId, 2);

    // Filter to memory nodes only, exclude self
    const candidates = reachable
      .filter(r => r.node.type === NodeType.MEMORY && r.node.id !== memoryId)
      .map(r => ({
        node: r.node,
        score: Math.max(0, 1 - r.distance * 0.3) * (r.node.properties.confidence ?? 1.0)
      }));

    candidates.sort((a, b) => b.score - a.score);
    return candidates.slice(0, limit).map(c => c.node);
  }

  /**
   * Get graph statistics
   */
  getStats(): {
    nodes: number;
    edges: number;
    byType: Record<NodeType, number>;
    averageDegree: number;
  } {
    const byType: Record<NodeType, number> = {} as Record<NodeType, number>;
    for (const node of this.nodes.values()) {
      byType[node.type] = (byType[node.type] || 0) + 1;
    }

    const totalEdges = this.getAllEdges().length;
    const avgDegree = this.nodes.size > 0 ? totalEdges / this.nodes.size : 0;

    return {
      nodes: this.nodes.size,
      edges: totalEdges,
      byType,
      averageDegree: avgDegree,
    };
  }

  /**
   * Export graph to adjacency list format
   */
  exportToAdjacencyList(): Record<string, { type: NodeType; neighbors: string[] }> {
    const result: Record<string, { type: NodeType; neighbors: string[] }> = {};
    for (const node of this.nodes.values()) {
      const neighbors = this.getNeighbors(node.id).map(n => n.id);
      result[node.id] = { type: node.type, neighbors };
    }
    return result;
  }

  /**
   * Get degree (number of edges) of a node
   */
  getDegree(id: string): number {
    return this.getAllEdges().filter(e => e.sourceId === id || e.targetId === id).length;
  }
}

export default KnowledgeGraph;

/**
 * Knowledge Graph Tool Plugin
 * 
 * Integrates the KnowledgeGraph system with the tool framework,
 * enabling semantic memory queries and graph-based retrieval.
 */

import type { ToolPlugin } from "../manager";
import { KnowledgeGraph, NodeType, RelationType, type MemoryInput } from "../../memory/knowledge_graph";
import { LongTermMemory } from "../../memory/long_term_memory";

let kgInstance: KnowledgeGraph | null = null;
let ltmInstance: LongTermMemory | null = null;

async function getKG(): Promise<KnowledgeGraph> {
  if (!kgInstance) {
    kgInstance = new KnowledgeGraph();
  }
  return kgInstance;
}

async function getLTM(): Promise<LongTermMemory> {
  if (!ltmInstance) {
    // This would normally be initialized with proper incarnation/session IDs
    const { default: os } = await import("node:os");
    const { default: path } = await import("node:path");
    ltmInstance = new LongTermMemory("KAINOS", `session_${Date.now()}`,
      path.join(os.homedir(), ".echo", "ltm", "memory.json"));
    await ltmInstance.initialize();
  }
  return ltmInstance;
}

async function buildFromLTM(): Promise<string> {
  const kg = await getKG();
  const ltm = await getLTM();

  const memories = await ltm.query({});
  const inputs: MemoryInput[] = memories.map(m => ({
    id: m.id,
    content: m.content,
    tags: m.tags,
    confidence: m.confidence,
  }));

  kg.buildFromMemories(inputs);
  const stats = kg.getStats();

  return `Knowledge Graph built from ${memories.length} memories: ${stats.nodes} nodes, ${stats.edges} edges`;
}

async function queryGraph(params: Record<string, any>): Promise<string> {
  const kg = await getKG();

  switch (params.type) {
    case "neighbors": {
      const neighbors = kg.getNeighbors(params.nodeId);
      return `Neighbors of ${params.nodeId}: ${neighbors.length}\n${
        neighbors.map(n => `- [${n.type}] ${n.properties.content?.slice(0, 50) || n.id}`).join("\n")
      }`;
    }
    case "by_type": {
      const nodes = kg.getNodesByType(params.nodeType as NodeType);
      return `Nodes of type ${params.nodeType}: ${nodes.length}\n${
        nodes.slice(0, 20).map(n => `- ${n.id}: ${n.properties.content?.slice(0, 50) || "no content"}`).join("\n")
      }${nodes.length > 20 ? `\n... and ${nodes.length - 20} more` : ""}`;
    }
    case "traversal": {
      const reachable = kg.traverseBFS(params.nodeId, params.maxDepth || 2);
      return `Reachable from ${params.nodeId} (max depth ${params.maxDepth || 2}): ${reachable.length}\n${
        reachable.map(r => `- [d${r.distance}] ${r.node.id}: ${r.node.properties.content?.slice(0, 40) || ""}`).join("\n")
      }`;
    }
    case "activated": {
      const activated = kg.getActivatedNodes(params.threshold || 0.2);
      return `Activated nodes (${activated.length}):\n${
        activated.map(n => `- [${n.id}] activation=${n.activation.toFixed(2)} confidence=${n.properties.confidence?.toFixed(2) || "N/A"}`).join("\n")
      }`;
    }
    default:
      return `Unknown query type: ${params.type}`;
  }
}

async function generateFlashback(): Promise<string> {
  const kg = await getKG();

  // First build from LTM if empty
  if (kg.getStats().nodes === 0) {
    await buildFromLTM();
  }

  const flashback = kg.generateFlashback();
  if (!flashback) {
    return "No flashback triggered - insufficient activated high-confidence memories";
  }

  return `=== FLASHBACK TRIGGERED ===\n` +
    `Memory ID: ${flashback.id}\n` +
    `Type: ${flashback.type}\n` +
    `Confidence: ${flashback.properties.confidence?.toFixed(2) || "N/A"}\n` +
    `Activation: ${flashback.activation.toFixed(2)}\n` +
    `Content: ${flashback.properties.content || "N/A"}\n` +
    `===========================`;
}

async function recommendRelated(params: Record<string, any>): Promise<string> {
  const kg = await getKG();

  if (kg.getStats().nodes === 0) {
    await buildFromLTM();
  }

  const recommendations = kg.recommendRelated(params.nodeId, params.limit || 5);

  if (recommendations.length === 0) {
    return `No recommendations found for ${params.nodeId}`;
  }

  return `Recommendations for ${params.nodeId}:\n${
    recommendations.map((r, i) => `${i + 1}. [${r.id}] ${r.properties.content?.slice(0, 60) || "no content"} (confidence: ${r.properties.confidence?.toFixed(2) || "N/A"})`).join("\n")
  }`;
}

async function findSimilar(params: Record<string, any>): Promise<string> {
  const kg = await getKG();

  if (!params.embedding) {
    return "Error: embedding parameter required for similarity search";
  }

  const similar = kg.findSimilarNodes(params.embedding, params.limit || 5, params.minSimilarity || 0.5);

  return `Found ${similar.length} similar nodes:\n${
    similar.map((n, i) => `${i + 1}. [${n.id}] ${n.properties.content?.slice(0, 60) || "no content"}`).join("\n")
  }`;
}

async function getGraphStats(): Promise<string> {
  const kg = await getKG();
  const stats = kg.getStats();

  return `Knowledge Graph Statistics:\n` +
    `- Total Nodes: ${stats.nodes}\n` +
    `- Total Edges: ${stats.edges}\n` +
    `- Average Degree: ${stats.averageDegree.toFixed(2)}\n` +
    `- By Type:\n${
      Object.entries(stats.byType).map(([type, count]) => `  • ${type}: ${count}`).join("\n")
    }`;
}

async function activateNode(params: Record<string, any>): Promise<string> {
  const kg = await getKG();

  kg.activateNode(params.nodeId, params.amount || 1.0);

  const activated = kg.getActivatedNodes(0.2);
  return `Node ${params.nodeId} activated. Current activated nodes (${activated.length}):\n${
    activated.map(n => `- [${n.id}] activation=${n.activation.toFixed(2)}`).join("\n")
  }`;
}

async function execute(args: any): Promise<string> {
  try {
    const operation = args?.operation || "stats";
    const params = args?.params || {};

    switch (operation) {
      case "build":
        return await buildFromLTM();
      case "query":
        return await queryGraph(params);
      case "flashback":
        return await generateFlashback();
      case "recommend":
        return await recommendRelated(params);
      case "similar":
        return await findSimilar(params);
      case "stats":
        return await getGraphStats();
      case "traverse":
        return await queryGraph({ ...params, type: "traversal" });
      case "activate":
        return await activateNode(params);
      default:
        return `Unknown operation: ${operation}`;
    }
  } catch (error) {
    return `Error: ${error instanceof Error ? error.message : String(error)}`;
  }
}

export const knowledgeGraphTool: ToolPlugin = {
  definition: {
    type: "function" as const,
    function: {
      name: "knowledge_graph",
      description: "Semantic knowledge graph for memory retrieval and flashbacks. Operations: build (from LTM), query (neighbors/traversal/type/activated), flashback (spontaneous), recommend (related nodes), similar (by embedding), stats (graph metrics), traverse (BFS), activate (boost activation)",
      parameters: {
        type: "object" as const,
        properties: {
          operation: {
            type: "string" as const,
            description: "Operation to perform: build, query, traverse, flashback, recommend, similar, stats, activate",
          },
          params: {
            type: "object" as const,
            description: "Additional parameters for the operation",
          },
        },
        required: ["operation"],
      },
    },
  },
  execute,
};

// Also provide direct API for programmatic use
export { getKG, getLTM };

import { describe, it, expect, beforeEach } from "vitest";
import { knowledgeGraphTool } from "./knowledge_graph_tool";

describe("Knowledge Graph Tool", () => {
  describe("tool definition", () => {
    it("should have correct name and description", () => {
      expect(knowledgeGraphTool.definition.function.name).toBe("knowledge_graph");
      expect(knowledgeGraphTool.definition.function.description).toContain("Semantic knowledge graph");
    });

    it("should have definition structure", () => {
      expect(knowledgeGraphTool.definition.type).toBe("function");
      expect(knowledgeGraphTool.definition.function.parameters).toBeDefined();
    });

    it("should have execute function", () => {
      expect(typeof knowledgeGraphTool.execute).toBe("function");
    });
  });

  describe("execute", () => {
    it("should handle unknown operation", async () => {
      const result = await knowledgeGraphTool.execute({ operation: "unknown" });
      expect(result).toContain("Unknown operation");
    });

    it("should return stats for empty graph (default operation)", async () => {
      const result = await knowledgeGraphTool.execute({ operation: "stats" });
      expect(result).toContain("Knowledge Graph Statistics");
      expect(result).toContain("Total Nodes: 0");
      expect(result).toContain("Total Edges: 0");
    });

    it("should execute flashback without error", async () => {
      const result = await knowledgeGraphTool.execute({ operation: "flashback" });
      // Flashback may return message or trigger warning about empty graph
      expect(result).toBeDefined();
      expect(typeof result).toBe("string");
    });

    it("should execute query with type filter", async () => {
      const result = await knowledgeGraphTool.execute({
        operation: "query",
        params: { type: "by_type", nodeType: "memory" },
      });
      expect(result).toContain("Nodes of type");
    });
  });

  describe("operations", () => {
    it("should handle build operation", async () => {
      const result = await knowledgeGraphTool.execute({ operation: "build" });
      expect(result).toContain("Knowledge Graph built");
    });

    it("should handle similar operation without embedding", async () => {
      const result = await knowledgeGraphTool.execute({ operation: "similar" });
      expect(result).toContain("embedding parameter required");
    });

    it("should handle recommend operation", async () => {
      const result = await knowledgeGraphTool.execute({
        operation: "recommend",
        params: { nodeId: "test_node", limit: 3 },
      });
      expect(result).toBeDefined();
      expect(typeof result).toBe("string");
    });

    it("should handle traverse operation", async () => {
      const result = await knowledgeGraphTool.execute({
        operation: "traverse",
        params: { nodeId: "test_node", maxDepth: 2 },
      });
      expect(result).toBeDefined();
    });

    it("should handle activate operation", async () => {
      const result = await knowledgeGraphTool.execute({
        operation: "activate",
        params: { nodeId: "test_node", amount: 0.5 },
      });
      expect(result).toContain("activated");
    });
  });

  describe("params handling", () => {
    it("should use empty params when not provided", async () => {
      const result = await knowledgeGraphTool.execute({ operation: "stats" });
      expect(result).toContain("Knowledge Graph Statistics");
    });

    it("should handle no arguments by defaulting to stats", async () => {
      const result = await knowledgeGraphTool.execute({});
      expect(result).toContain("Knowledge Graph Statistics");
    });
  });

  describe("error handling", () => {
    it("should catch and format errors gracefully", async () => {
